class Solution:
    def calcWriteIndex(self, capacity: int, align: int, read_index: int, write_index: int, pkt_size: int) -> int:
        # 对异常输入做保护，正常测试数据一般满足题目约束
        if capacity <= 0 or align <= 0 or pkt_size < 0:
            return -1

        # 计算当前缓冲区中的可用空间
        # 当读写索引相等时，题目规定缓冲区为空，因此可用空间是完整容量
        if write_index == read_index:
            free_space = capacity
        elif write_index < read_index:
            # 写索引在读索引前方，只能使用 [write_index, read_index) 这一段
            free_space = read_index - write_index
        else:
            # 写索引在读索引后方，可用空间跨过缓冲区末尾并回绕到读索引前
            free_space = capacity - write_index + read_index

        # 将 write_index 向上调整到 align 的整数倍
        remainder = write_index % align
        if remainder == 0:
            aligned_start = write_index
        else:
            aligned_start = write_index + align - remainder

        # 计算为了对齐而跳过的字节数
        if aligned_start >= capacity:
            # 对齐点到达或超过末尾时，写入起点回绕到 0
            padding = capacity - write_index
            aligned_start = 0
        else:
            padding = aligned_start - write_index

        # 本次写入实际消耗包括对齐跳过的空间和数据包本身
        need_space = padding + pkt_size

        # 如果实际消耗超过当前可用空间，则会覆盖未读取数据
        if need_space > free_space:
            return -1

        # 写入数据包后，新的写索引是数据包结束位置，超过末尾则取模回绕
        return (aligned_start + pkt_size) % capacity
```

